class ProjectProgressWidget extends HTMLElement{constructor(){super();this.attachShadow({mode: 'open'});}static get observedAttributes(){return ['project-id','title','status'];}connectedCallback(){this.render();this.loadProject();}attributeChangedCallback(){this.render();}render(){const title=this.getAttribute('title')||'Project Progress';const status=this.getAttribute('status')||'active';this.shadowRoot.innerHTML=`<style>:host{display: block;}.project-container{background: rgba(255,255,255,0.05);backdrop-filter: blur(10px);border-radius: 16px;padding: 24px;border: 1px solid rgba(255,255,255,0.1);}.project-header{display: flex;justify-content: space-between;align-items: center;margin-bottom: 20px;}.project-title{font-size: 20px;font-weight: 600;color: #ffffff;font-family: 'Space Grotesk',sans-serif;}.project-status{padding: 6px 12px;border-radius: 20px;font-size: 12px;font-weight: 600;text-transform: uppercase;}.project-status.active{background: rgba(0,230,118,0.15);color: #00e676;}.project-status.pending{background: rgba(255,145,0,0.15);color: #ff9100;}.project-status.completed{background: rgba(0,229,255,0.15);color: #00e5ff;}.project-status.delayed{background: rgba(255,23,68,0.15);color: #ff1744;}.project-list{display: flex;flex-direction: column;gap: 16px;}.project-item{padding: 16px;border-radius: 12px;background: rgba(255,255,255,0.03);transition: all 0.3s ease;}.project-item:hover{background: rgba(255,255,255,0.06);}.project-item-header{display: flex;justify-content: space-between;align-items: center;margin-bottom: 12px;}.project-name{font-size: 15px;font-weight: 600;color: #ffffff;}.project-percentage{font-size: 14px;font-weight: 700;color: #00e5ff;}.progress-bar{height: 8px;background: rgba(255,255,255,0.1);border-radius: 4px;overflow: hidden;margin-bottom: 12px;}.progress-fill{height: 100%;background: linear-gradient(90deg,#00e5ff,#00b8d4);border-radius: 4px;transition: width 1s ease;position: relative;}.progress-fill::after{content: '';position: absolute;top: 0;left: 0;right: 0;bottom: 0;background: linear-gradient(90deg,transparent,rgba(255,255,255,0.3),transparent);animation: shimmer 2s infinite;}@keyframes shimmer{0%{transform: translateX(-100%);}100%{transform: translateX(100%);}}.project-meta{display: flex;justify-content: space-between;align-items: center;font-size: 12px;color: rgba(255,255,255,0.5);}.project-client{display: flex;align-items: center;gap: 6px;}.project-client-avatar{width: 20px;height: 20px;border-radius: 50%;background: linear-gradient(135deg,#00e5ff,#d500f9);display: flex;align-items: center;justify-content: center;font-size: 10px;font-weight: 700;color: #fff;}.project-deadline{display: flex;align-items: center;gap: 4px;}.project-empty{text-align: center;padding: 40px 20px;color: rgba(255,255,255,0.4);}.project-empty span{font-size: 48px;display: block;margin-bottom: 12px;}.view-all-link{display: block;text-align: center;padding: 14px;margin-top: 16px;color: #00e5ff;text-decoration: none;font-size: 14px;font-weight: 600;border-radius: 12px;background: rgba(0,229,255,0.1);transition: all 0.2s ease;}.view-all-link:hover{background: rgba(0,229,255,0.15);}</style><div class="project-container"><div class="project-header"><h3 class="project-title">${title}</h3><span class="project-status ${status}">${status}</span></div><div class="project-list" id="projectList"><div class="project-empty"><span class="material-symbols-outlined">folder_open</span>No projects yet</div></div><a href="/admin/projects.html" class="view-all-link">View All Projects →</a></div>`;}async loadProject(){if(window.AdminAPI?.loadProjects){try{const projects=await window.AdminAPI.loadProjects({limit: 5});this.renderProjects(projects);return;}catch(error){}}this.renderProjects(this.getDemoProjects());}getDemoProjects(){return [{id: 1,name: 'Website Redesign-Container Coffee',client: 'Container Coffee Hub',progress: 75,deadline: '2026-03-25',status: 'active'},{id: 2,name: 'SEO Optimization Campaign',client: 'Sa Đéc Tourism',progress: 45,deadline: '2026-04-10',status: 'active'},{id: 3,name: 'Social Media Content Calendar',client: 'Mekong Handicrafts',progress: 90,deadline: '2026-03-18',status: 'pending'},{id: 4,name: 'Brand Identity Package',client: 'Dong Thap Eco Lodge',progress: 30,deadline: '2026-04-30',status: 'delayed'},{id: 5,name: 'Google Ads Campaign Setup',client: 'An Giang Travel',progress: 100,deadline: '2026-03-10',status: 'completed'}];}renderProjects(projects){const projectList=this.shadowRoot.getElementById('projectList');if(!projectList)return;if(!projects||projects.length===0){projectList.innerHTML=`<div class="project-empty"><span class="material-symbols-outlined">folder_open</span>No projects yet</div>`;return;}projectList.innerHTML=projects.map((project,index)=>`<div class="project-item" style="animation-delay: ${index*0.1}s"><div class="project-item-header"><div class="project-name">${project.name}</div><div class="project-percentage">${project.progress}%</div></div><div class="progress-bar"><div class="progress-fill" style="width: ${project.progress}%"></div></div><div class="project-meta"><div class="project-client"><div class="project-client-avatar">${project.client.charAt(0)}</div><span>${project.client}</span></div><div class="project-deadline"><span class="material-symbols-outlined" style="font-size: 14px;">calendar_today</span><span>${this.formatDate(project.deadline)}</span></div></div></div>`).join('');}formatDate(dateString){const date=new Date(dateString);return date.toLocaleDateString('vi-VN',{month: 'short',day: 'numeric'});}}customElements.define('project-progress-widget',ProjectProgressWidget);